// AgentCompactRow Compact row exemplar — only changed fields, no full values.
type AgentCompactRow struct {
	ChangedFields    *[]AgentFieldPatch `json:"changed_fields,omitempty"`
	InitialSignature string             `json:"initial_signature_"`
	IsStateFlip      bool               `json:"is_state_flip"`

	// LeftIssues Compact list of fields with issues on one row side.
	LeftIssues *AgentIssueSummary        `json:"left_issues,omitempty"`
	LeftState  *AgentCompactRowLeftState `json:"left_state"`

	// RightIssues Compact list of fields with issues on one row side.
	RightIssues *AgentIssueSummary         `json:"right_issues,omitempty"`
	RightState  *AgentCompactRowRightState `json:"right_state"`
}

// AgentCompactRowLeftState defines model for AgentCompactRow.LeftState.
type AgentCompactRowLeftState string

// AgentCompactRowRightState defines model for AgentCompactRow.RightState.
type AgentCompactRowRightState string

// AgentFieldPatch A single changed field with before/after values and diff flags.
type AgentFieldPatch struct {
	After          interface{} `json:"after"`
	AlertChanged   bool        `json:"alert_changed"`
	Before         interface{} `json:"before"`
	Field          string      `json:"field"`
	ValueChanged   bool        `json:"value_changed"`
	WarningChanged bool        `json:"warning_changed"`
}

// AgentIssueSummary Compact list of fields with issues on one row side.
type AgentIssueSummary struct {
	AlertFields   *[]string               `json:"alert_fields,omitempty"`
	FieldValues   *map[string]interface{} `json:"field_values,omitempty"`
	WarningFields *[]string               `json:"warning_fields,omitempty"`
}

