// DryRunJobFullSchema Full representation of a dry-run job returned by the API.
//
// Contains two summary-related fields:
// - “summary“ — pre-rendered Markdown stored in the DB.
// - “structured_summary“ — a structured Pydantic object computed on-the-fly from “metrics“.
type DryRunJobFullSchema struct {
	DatasetID int `json:"dataset_id"`

	// ExecutionContext Frozen execution context for deterministic replays.
	ExecutionContext        *ExecutionContextSpec        `json:"execution_context,omitempty"`
	ID                      int                          `json:"id"`
	IngestionJobID          *int                         `json:"ingestion_job_id"`
	Metrics                 *DryRunJobFullSchema_Metrics `json:"metrics"`
	NondeterminismCheckMode *string                      `json:"nondeterminism_check_mode,omitempty"`

	// NondeterminismReport Results of nondeterminism verification pass.
	NondeterminismReport     *NondeterminismReport `json:"nondeterminism_report,omitempty"`
	NondeterminismSampleSize *int                  `json:"nondeterminism_sample_size,omitempty"`
	PinnedSignatures         *[]string             `json:"pinned_signatures"`
	RuleLoadErrors           *[]RuleLoadError      `json:"rule_load_errors"`
	RuleRunSpecs             []RuleRunSpec         `json:"rule_run_specs"`

	// Sampling Sampling metadata stored in DryRunJob.sampling field.
	//
	// This TypedDict captures the complete sampling process metadata, including
	// configuration, pool statistics, and processing results.
	//
	// All fields except 'eligible' and 'scanned' are required and set during
	// pool building. The 'eligible' and 'scanned' fields are added after
	// wave processing completes.
	//
	// Attributes:
	//     cap: Maximum number of signatures to include in the sampling pool
	//     wave_size: Number of signatures to pick per wave
	//     alpha_pref: Preference ratio for quarantine vs clean rows (0.0 - 1.0)
	//     weights: Score weights for alert matching and nonempty columns
	//     strata_frame_in_pool: Per-stratum counts of rows in the pool
	//     pins_inserted: Number of pinned signatures successfully found and inserted
	//     pins_missing: Number of pinned signatures not found in data
	//     pins_truncated: Number of pinned signatures excluded due to cap limit
	//     eligible_q: Total number of eligible quarantine rows in the dataset
	//     eligible_c: Total number of eligible clean rows in the dataset
	//     eligible: Total number of eligible rows processed (added after processing)
	//     scanned: Total number of rows scanned during processing (added after processing)
	Sampling   SamplingMetadata  `json:"sampling"`
	SnapshotAt *time.Time        `json:"snapshot_at"`
	State      IngestionJobState `json:"state"`

	// StructuredSummary Structured summary computed on-the-fly from raw metrics.
	StructuredSummary *DryRunJobFullSchema_StructuredSummary `json:"structured_summary,omitempty"`
	Summary           *string                                `json:"summary"`
}

