// HistoryTinySchema defines model for HistoryTinySchema.
type HistoryTinySchema struct {
	// CreatedAt When this history item was recorded.
	CreatedAt time.Time `json:"created_at"`

	// DatasetID The id of the dataset, if this item is related to a dataset.
	DatasetID *int `json:"dataset_id"`

	// DatasetName The name of the dataset, if this item is related to a dataset.
	DatasetName *string `json:"dataset_name"`

	// DeletedAt When this history item was deleted.
	DeletedAt     *time.Time          `json:"deleted_at"`
	DeletedByUser *UserInfoTinySchema `json:"deleted_by_user,omitempty"`
	ID            int                 `json:"id"`

	// IsDeleted Tri-state flag tracking undo/redo status:
	//         • FALSE (default): History item is applied/active (normal state, not undone).
	//         • TRUE: History item is undone (fully removed from active chain; redo-able).
	//         • NULL: Partially undone (mixed outcome during bulk undo/redo operations).
	//
	//         When a user performs undo on a history item:
	//         - If all affected rows succeed → is_deleted becomes TRUE
	//         - If some rows succeed and some fail → is_deleted becomes NULL
	//         - If no rows succeed → is_deleted remains FALSE
	//
	//         During redo, the reverse transitions occur (TRUE/NULL → FALSE).
	//         Frontend should display NULL state as "partially undone/redone" requiring retry.
	//
	//         Note: Cannot be enforced via SQL CHECK beyond NULL/boolean typing.
	IsDeleted *bool             `json:"is_deleted,omitempty"`
	Model     ModelsWithHistory `json:"model"`

	// ModelID Which model id (int) is this about?
	ModelID HistoryTinySchema_ModelID `json:"model_id"`

	// NewPath The new path to the item.
	NewPath *[]string `json:"new_path"`

	// OldValue The old value before the change was applied.
	OldValue *string `json:"old_value"`

	// Operation This is the simplified version of history action
	Operation SimpleHistoryAction `json:"operation"`

	// Path The path to the item.
	Path []string            `json:"path"`
	User *UserInfoTinySchema `json:"user,omitempty"`

	// Value The new value.
	Value *string `json:"value"`

	// VersionID The version id of the model when this change happened.
	VersionID int `json:"version_id"`
}

