// RuleState Lifecycle state for RuleRevision (rule template/definition).
//
// State transitions:
//
//		draft -> enabled -> disabled (when no review policy)
//		draft -> in_review -> enabled -> disabled (when there is a review policy)
//
//	  - draft: Pending review/approval. Cannot be instantiated as DatasetRule.
//	  - in_review: Submitted for review, visible in Reviews Inbox
//	  - enabled: Available for use. Can create new DatasetRules.
//	  - disabled: Deprecated/sunset. No new DatasetRules allowed.
//	    Existing DatasetRules must be disabled before transitioning here.
type RuleState string

// SamplerWeights Score weights for DryRunSampler ranking.
//
// These weights control how rows are scored and ranked for sampling.
// Both keys are required.
//
// Attributes:
//
//	alert: Weight for rows with matching focus alert IDs
//	nonempty: Weight for rows with non-empty values in touched columns
type SamplerWeights struct {
	Alert    float32 `json:"alert"`
	Nonempty float32 `json:"nonempty"`
}

// SamplingMetadata Sampling metadata stored in DryRunJob.sampling field.
//
// This TypedDict captures the complete sampling process metadata, including
// configuration, pool statistics, and processing results.
//
// All fields except 'eligible' and 'scanned' are required and set during
// pool building. The 'eligible' and 'scanned' fields are added after
// wave processing completes.
//
// Attributes:
//
//	cap: Maximum number of signatures to include in the sampling pool
//	wave_size: Number of signatures to pick per wave
//	alpha_pref: Preference ratio for quarantine vs clean rows (0.0 - 1.0)
//	weights: Score weights for alert matching and nonempty columns
//	strata_frame_in_pool: Per-stratum counts of rows in the pool
//	pins_inserted: Number of pinned signatures successfully found and inserted
//	pins_missing: Number of pinned signatures not found in data
//	pins_truncated: Number of pinned signatures excluded due to cap limit
//	eligible_q: Total number of eligible quarantine rows in the dataset
//	eligible_c: Total number of eligible clean rows in the dataset
//	eligible: Total number of eligible rows processed (added after processing)
//	scanned: Total number of rows scanned during processing (added after processing)
type SamplingMetadata struct {
	AlphaPref     float32 `json:"alpha_pref"`
	Cap           int     `json:"cap"`
	Eligible      *int    `json:"eligible,omitempty"`
	EligibleC     int     `json:"eligible_c"`
	EligibleQ     int     `json:"eligible_q"`
	PinsInserted  int     `json:"pins_inserted"`
	PinsMissing   int     `json:"pins_missing"`
	PinsTruncated int     `json:"pins_truncated"`
	Scanned       *int    `json:"scanned,omitempty"`

	// StrataFrameInPool Per-stratum counts of rows in the sampling pool.
	//
	// Attributes:
	//     quarantine: Number of quarantine rows in the pool
	//     clean: Number of clean rows in the pool
	StrataFrameInPool StrataFrameInPool `json:"strata_frame_in_pool"`
	WaveSize          int               `json:"wave_size"`

	// Weights Score weights for DryRunSampler ranking.
	//
	// These weights control how rows are scored and ranked for sampling.
	// Both keys are required.
	//
	// Attributes:
	//     alert: Weight for rows with matching focus alert IDs
	//     nonempty: Weight for rows with non-empty values in touched columns
	Weights SamplerWeights `json:"weights"`
}

